mapper.select:
select
    from_id as fromId
    ,to_id as toId
    ,if(status = 1, 1, 0) as status
from im_friendship
where from_id = #{fromId}
and app_id = #{appId}
and to_id in

    #{id}

select a.fromId, a.toId, case when if(a.status = 1, 1, 0) = 1 and if(b.status = 1, 1, 0) = 1 then 1 when if(a.status = 1, 1, 0) = 1 and if(b.status = 1, 1, 0) = 0 then 2 when if(a.status = 1, 1, 0) = 0 and if(b.status = 1, 1, 0) = 1 then 3 else 4 end as status from ( select from_id as fromId, to_id as toId, if(status=1, 1, 0) as status from im_friendship where from_id=#{fromId} and app_id=#{appId} and to_id in
#{id}
) as a left join ( select from_id as fromId, to_id as toId, if(status=1, 1, 0) as status from im_friendship where to_id=#{fromId} and app_id=#{appId} and from_id in
#{id}
) as b on b.fromId=a.toId and a.fromId=b.toId

select
    from_id as fromId
    ,to_id as toId
    ,if(black = 1, 1, 0) as status
from im_friendship
where from_id = #{fromId}
and app_id = #{appId}
and to_id in

    #{id}

select a.fromId, a.toId, case when if(a.black = 1, 1, 0) = 1 and if(b.black = 1, 1, 0) = 1 then 1 when if(a.black = 1, 1, 0) = 1 and if(b.black = 1, 1, 0) = 0 then 2 when if(a.black = 1, 1, 0) = 0 and if(b.black = 1, 1, 0) = 1 then 3 else 4 end as status from ( select from_id as fromId, to_id as toId, if(black=2, 1, 0) as black from im_friendship where from_id=#{fromId} and app_id=#{appId} and to_id in
#{id}
) as a left join ( select from_id as fromId, to_id as toId, if(black=2, 1, 0) as black from im_friendship where to_id=#{fromId} and app_id=#{appId} and from_id in
#{id}
) as b on b.fromId=a.toId and a.fromId=b.toId
